import { IconProps } from "@/types/shared.types";

export function FilterIcon({
  className,
  color = "#414651",
  size = 20,
}: IconProps) {
  return (
    <svg
      width={size}
      height={size}
      viewBox="0 0 20 20"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      className={className}
    >
        <path d="M5 10H15M2.5 5H17.5M7.5 15H12.5" stroke={color} strokeWidth="1.67" strokeLinecap="round" strokeLinejoin="round"/>
    </svg>
  );
} 