import { IconProps } from "@/types";

export function LogoIcon({
    className,
}: IconProps) {
    return (
        <svg 
            width="53" 
            height="51" 
            viewBox="0 0 53 51" 
            fill="none"
            className={className} 
            xmlns="http://www.w3.org/2000/svg" 
            xmlnsXlink="http://www.w3.org/1999/xlink"
        >
            <rect width="53" height="51" fill="url(#pattern0_2001_493)"/>
            <defs>
            <pattern id="pattern0_2001_493" patternContentUnits="objectBoundingBox" width="1" height="1">
                <use xlinkHref="#image0_2001_493" transform="matrix(0.00746269 0 0 0.00775194 -1.36567 -1.43411)"/>
            </pattern>
            <image id="image0_2001_493" width="500" height="500" preserveAspectRatio="none" xlinkHref="data:image/png;base64,"/>
            </defs>
        </svg>      
    );
}


